# Day 12: 5 Coding Challenges

# 1. FizzBuzz
for i in range(1, 21):
    if i % 15 == 0: print("FizzBuzz", end=" ")
    elif i % 3 == 0: print("Fizz", end=" ")
    elif i % 5 == 0: print("Buzz", end=" ")
    else: print(i, end=" ")
print()

# 2. Sum of Digits
def sum_digits(n):
    total = 0
    while n > 0:
        total += n % 10
        n //= 10
    return total
print(f"sum_digits(1234) = {sum_digits(1234)}")

# 3. Reverse String
def reverse(s):
    result = ""
    for ch in s: result = ch + result
    return result
print(f"reverse('hello') = {reverse('hello')}")

# 4. Find Max
def find_max(nums):
    m = nums[0]
    for n in nums[1:]:
        if n > m: m = n
    return m
print(f"max([3,7,2,9]) = {find_max([3,7,2,9])}")

# 5. Palindrome
def is_palindrome(s):
    s = s.lower()
    return s == s[::-1]
for w in ["racecar", "hello", "madam"]:
    print(f"  '{w}' → {is_palindrome(w)}")
